spec.volumes:
${[
  {"name": "thunder-config", "configMap": {"name": metadata.componentName + "-config"}},
  {"name": "gate-config", "configMap": {"name": metadata.componentName + "-gate-config"}},
  {"name": "console-config", "configMap": {"name": metadata.componentName + "-console-config"}},
  {"name": "sqlite-data", "persistentVolumeClaim": {"claimName": metadata.componentName + "-sqlite"}}
] + configurations.toVolumes().map(v, {"name": v.name, "configMap": {"name": v.configMap.name}})}

spec.hostnames:
${[gateway.ingress.external.?http, gateway.ingress.external.?https]
  .filter(g, g.hasValue()).map(g, g.value().host).distinct()
  .map(h, metadata.environmentName + "-" + metadata.componentName + "-" + metadata.componentNamespace + "." + h)}

